/* Якщо видобуток успішний, поверніть правдивий; в іншому випадку, якщо під час процесу видобутку виникне якась помилка (наприклад, файл не знайдений, помилка дозволу, не може видобути весь вміст), поверніть неправдивий. Справа: Наступний код показує, як видобути вміст файлу неправдивого до даного маршруту з бібліотекою лібархіва. bool extract_archive(struct archive *src, const char *dest_path) {Struktural archive *out; structural archive_entry *entry *entry; INTIVE flags = ARCHIVE_src_EXTRACT_TIME ARCHIVE_TRACT_PERM; int r; char_CH_TIME  */// Ініціалізуйте письменника архівів    out = archive_write_disk_new();
    if (!out) {
        return false;
    }
    archive_write_disk_set_options(out, flags);
// Читати і витягнути кожен запис    while ((r = archive_read_next_header(src, &entry)) == ARCHIVE_OK) {
        // Створюйте повний шлях        snprintf(full_path, sizeof(full_path), "%s/%s",
                dest_path, archive_entry_pathname(entry));
        archive_entry_set_pathname(entry, full_path);
// Напишіть заголовки        r = archive_write_header(out, entry);
        if (r != ARCHIVE_OK) {
            archive_write_free(out);
            return false;
        }
// Копіювання даних        const void *buff;
        size_t size;
        la_int64_t offset;
        while ((r = archive_read_data_block(src, &buff, &size, &offset)) == ARCHIVE_OK) {
            if (archive_write_data_block(out, buff, size, offset) != ARCHIVE_OK) {
                archive_write_free(out);
                return false;
            }
        }
        if (r != ARCHIVE_EOF) {
            archive_write_free(out);
            return false;
        }
    }

    archive_write_free(out);
    return r == ARCHIVE_EOF ? true : false;
}


